const query = $.input.dateQuery;
const tz = $.input.timezone || 'UTC';
const currentTime = $.steps.getCurrentTime.output || '';

let prompt = 'You are a date and time calculation expert. Answer the following date/time query with precision and clarity.

';
prompt += 'CURRENT DATE/TIME REFERENCE:
' + currentTime + '

';
prompt += 'DEFAULT TIMEZONE: ' + tz + '

';
prompt += 'QUERY: ' + query + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Perform the requested date/time calculation or conversion
';
prompt += '- Show the result in multiple useful formats
';
prompt += '- Explain the calculation step by step
';
prompt += '- Include relevant context (weekday names, relative descriptions)
';
prompt += '- Account for leap years, DST, and timezone differences when relevant

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "query": "the original query",
';
prompt += '  "result": "primary answer in plain language",
';
prompt += '  "formats": {
';
prompt += '    "iso": "YYYY-MM-DDTHH:MM:SSZ",
';
prompt += '    "human": "Wednesday, March 25, 2026 3:00 PM UTC",
';
prompt += '    "relative": "45 days from now",
';
prompt += '    "unix": 0
';
prompt += '  },
';
prompt += '  "explanation": "step-by-step calculation explanation",
';
prompt += '  "additionalInfo": ["helpful related fact 1", "fact 2"],
';
prompt += '  "timezoneConversions": [{ "timezone": "name", "time": "formatted time" }]
';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { query: $.input.dateQuery, result: raw, formats: {}, explanation: '', additionalInfo: [], timezoneConversions: [] }; }

const ai = $.steps.parseAI.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Date/Time Calculator', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Query:* ' + (ai.query || $.input.dateQuery) } });
blocks.push({ type: 'divider' });

const resultText = (ai.result || 'No result computed.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Result:*\n' + resultText } });

const f = ai.formats || {};
if (f.iso || f.human || f.relative) {
  const fields = [];
  if (f.iso) fields.push({ type: 'mrkdwn', text: '*ISO:*\n`' + f.iso + '`' });
  if (f.human) fields.push({ type: 'mrkdwn', text: '*Human:*\n' + f.human });
  if (f.relative) fields.push({ type: 'mrkdwn', text: '*Relative:*\n' + f.relative });
  if (f.unix) fields.push({ type: 'mrkdwn', text: '*Unix:*\n`' + f.unix + '`' });
  blocks.push({ type: 'section', fields: fields.slice(0, 4) });
}

if (ai.explanation) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Explanation:*\n' + ai.explanation.slice(0, 1800) } });
}

if (ai.timezoneConversions && ai.timezoneConversions.length > 0) {
  blocks.push({ type: 'divider' });
  let tzText = '*Timezone Conversions:*\n';
  ai.timezoneConversions.slice(0, 6).forEach(tz => {
    tzText += '- *' + tz.timezone + ':* ' + tz.time + '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: tzText.slice(0, 1800) } });
}

if (ai.additionalInfo && ai.additionalInfo.length > 0) {
  let infoText = ai.additionalInfo.slice(0, 3).join(' | ');
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: infoText.slice(0, 1800) }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI' }] });

const fallbackText = 'Date/Time: ' + (ai.query || '').slice(0, 40) + ' = ' + (ai.result || '').slice(0, 100);
return { blocks, fallbackText };
